def gen_test_data():
    ai_client = OpenAI(api_key="sk-191f9be71cb54ebfa9776bc46a9005fe",
                       base_url="https://dashscope.aliyuncs.com/compatible-mode/v1")
    count = 10
    data_format = "json"
    # data_format = "sql"
    example_result = '{"id", 1, "username": "张三", "email": "test@qq.com"}'
    # example_result = "insert into users(id, username, email, age) value(1, '张三', '123@qq.com', 20)"
    prompt = f"""
        1. 基础配置：
           - 数据量：{count}条
           - 数据格式：{data_format}
           - 语言：中文
        2. 结果示例参考：
           {example_result}
        3. 字段配置：
           1. 字段名：id
              - 类型：ID
              - 描述：用户唯一标识符
           2. 字段名：username
              - 类型：字符串
              - 描述：用户登录名，4-16位字母数字组合
           3. 字段名：email
              - 类型：邮箱
              - 描述：用户电子邮箱地址
           4. 字段名：age
              - 类型：数字
              - 描述：18到45之间
    """
    # 调用大模型
    response = ai_client.chat.completions.create(
        model="qwen3-max",  # 可根据实际配置调整模型名称
        messages=[
            {"role": "system", "content": f"上下文"},
            {"role": "user", "content": prompt}
        ]
    )
    print(response)
    generated_data = response.choices[0].message.content
    print(generated_data)
    # 使用正则表达式提取数据
    import re, json
    # 提取```json 中的数据
    generated_data = re.search(r"```json(.*?)```", generated_data, re.DOTALL).group(1)
    print(f"生成的数据1: {generated_data}", type(generated_data))
    # 转换成json对象
    generated_data = json.loads(generated_data)
    print(f"生成的数据2: {generated_data}", type(generated_data))


